function handleFile(f){if(!f)return;var r=new FileReader();r.onload=function(ev){pendingImg=ev.target.result;$('cf-pt').src=pendingImg;$('cf-imgprev').className='has-img';$('cf-sb').disabled=false};r.readAsDataURL(f)}

